+
+func skipForEnergy(pcm []int16, threshDb float64) bool {
+	if threshDb == 0 {
+		return false
+	}
+	db := rmsDbFS(pcm)
+	return db < threshDb
+}
+
+func rmsDbFS(pcm []int16) float64 {
+	if len(pcm) == 0 {
+		return -120
+	}
+	var sum float64
+	for _, s := range pcm {
+		f := float64(s) / 32768.0
+		sum += f * f
+	}
+	rms := math.Sqrt(sum / float64(len(pcm)))
+	if rms == 0 {
+		return -120
+	}
+	return 20 * math.Log10(rms)
+}
